import React from 'react';
import { Routes, Route } from "react-router-dom";
// import { BrowserRouter as Router, Routes, Route } from "react-router-dom";

import AdminLayout from './Components/AdminLayout.js';


//HomePage
import Header1 from './Components/HomePage/Header1.jsx';
import Home1 from './Components/HomePage/Home1.jsx';
import About1 from './Components/HomePage/About1.jsx';
import LoginPortal1 from './Components/HomePage/LoginPortal1.jsx';
import Footer1 from './Components/HomePage/Footer1.jsx';

//Login Form
import JobApplicantForm from './Components/LoginPages/JobApplicantForm.jsx';
import CompanyForm from './Components/LoginPages/CompanyForm.jsx';
import JobApplicantRegister from './Components/LoginPages/JobApplicantRegister.jsx';
import CompanyRegister from './Components/LoginPages/CompanyRegister.jsx';
import AdminLogin from './Components/LoginPages/AdminLogin.jsx';

//Portal for Both JobApplicant and Company
import JobApplicantPage from './Components/PortalInterface/JobApplicantPage.jsx';
import CompanyPage from './Components/PortalInterface/CompanyPage.jsx';
import Admin from './Components/PortalInterface/Admin.jsx';

function App() {
  return (
    
      <Routes>
        {/* Single-page scrolling layout */}
        <Route path="/" element={<SinglePageLayout />} />

        {/* Separate page for AdminLogin */}
        <Route
          path="/AdminLogin"
          element={
            <>
              <Header1 />
              <AdminLogin />
              <Footer1 />
            </>
          }
        />

        <Route
          path="/AdminInterface"
          element={
            <>
              <Header1 />
              <Admin />
              <Footer1 />
            </>
          }
        />

        <Route 
        path='/JobApplicantLogin'
        element={
          <>
            <Header1 />
            <JobApplicantForm />
            <Footer1 />
          </>
        }
        />

        <Route 
        path='/JobApplicantRegister'
        element={
          <>
            <Header1 />
            <JobApplicantRegister />
            <Footer1 />
          </>
        }
        />

        <Route 
        path='/saveApplicantDetails'
        element={
          <>
            <Header1 />
            <JobApplicantPage />
            <Footer1 />
          </>
        }
        />

        <Route 
        path='/CompanyLogin'
        element={
          <>
            <Header1 />
            <CompanyForm />
            <Footer1 />
          </>
        }
        />

        <Route 
        path='/CompanyRegister'
        element={
          <>
            <Header1 />
            <CompanyRegister />
            <Footer1 />
          </>
        }
        />

        <Route 
        path='/saveCompanyDetails'
        element={
          <>
            <Header1 />
            <CompanyPage />
            <Footer1 />
          </>
        }
        />

      </Routes>
    

    

  );
}

// Single-page layout component
function SinglePageLayout() {
  return (
    <>
      <Header1 />
      <Home1 />
      <LoginPortal1 />
      <About1 />
      <Footer1 />
    </>
  );
}

export default App;
