import React ,{ useState } from 'react'
import { useNavigate } from 'react-router-dom';

import "./LoginMain.css";
import "./JobApplicantForm.css";

import "../HomePage/LoginPortal1";

export default function JobApplicantRegister() {

  const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [confirmPassword, setConfirmPassword] = useState("");
    const [message, setMessage] = useState("");

    const navigate = useNavigate(); // Initialize useNavigate

    const handleRegister = async (e) => {
        e.preventDefault();

        if (password !== confirmPassword) {
            setMessage("Passwords do not match");
            return;
        }

        try {
            const response = await fetch("http://localhost:5000/JobApplicantRegister", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    applicant_email: email,
                    applicant_password: password,
                    confirmPassword: confirmPassword,
                }),
            });

            const data = await response.json();
            setMessage(data.message);

            if (response.ok) {
                // alert("Registration successful!");
                navigate("/saveApplicantDetails"); // Redirect to login page
            } else {
                alert("Error: " + data.message);
            }
        } catch (error) {
            console.error("Error during registration:", error);
            setMessage("An error occurred. Please try again.");
        }
    };

  

  return (
    <div className='loginmain d-flex justify-content-center align-items-center m-3 p-4 vh-100'>

      <div className='loginform-container'>

        <div className='loginform '>

            <p className='loginform-quote'>It Always Seems Impossible Until It's Done!</p>

            <form onSubmit={handleRegister}>
            <div className='form-login'>
            <input className='loginform-input' type="email" placeholder='Enter Email ' onChange={(e) => setEmail(e.target.value)} required/> <br />
            <input className='loginform-input' type="password" placeholder='Password ' onChange={(e) => setPassword(e.target.value)} required /> <br />
            <input className='loginform-input' type="password" placeholder='Confirm Password ' onChange={(e) => setConfirmPassword(e.target.value)} required /> <br />
            <button className="loginform-btn" type='submit'>SUBMIT</button>
            </div>
            </form>
            {message && <p>{message}</p>}
        </div>
        <div className='loginimage'>

        </div>

      </div>
    </div>
  )
}
